<?php if (!$totals['items']): ?><div class="empty-state compact"><p>Coșul tău așteaptă prima alegere.</p><a class="button" href="<?= e(url('/shop')) ?>">Descoperă colecția</a></div><?php else: ?><div class="drawer-items"><?php foreach ($totals['items'] as $item): $custom=json_decode((string)($item['customization_json']??''),true)?:[]; ?><div class="drawer-item"><img src="<?= e(url($item['image_path'])) ?>" alt="" width="72" height="86"><div><strong><?= e($item['name']) ?></strong><small><?= e($item['variant_label'] ?: 'Standard') ?> · <?= (int)$item['quantity'] ?> buc.</small><?php if(($custom['type']??'')==='gift_box'): ?><small class="gift-cart-note"><?= ($custom['role']??'')==='component'?'Componentă pentru':'Cutie' ?> <?= e($custom['template_name']??'Gift Box') ?></small><?php if(($custom['role']??'')==='box'&&!empty($custom['gift_message'])): ?><small class="gift-cart-message">„<?= e($custom['gift_message']) ?>”</small><?php endif; ?><?php endif; ?></div><b><?= money((int)$item['price_minor']*(int)$item['quantity']) ?></b></div><?php endforeach; ?></div><div class="drawer-total"><span>Subtotal</span><strong><?= money($totals['subtotal_minor']) ?></strong></div><a class="button" href="<?= e(url('/checkout')) ?>">Finalizează comanda</a><a class="button button-outline" href="<?= e(url('/cos')) ?>">Vezi coșul</a><?php endif; ?>